	public ModelAndView getM_AIDPView(String reportId, String fromdate, String todate, String currency, String dtltype,
			Pageable pageable, String type, BigDecimal version) {

		ModelAndView mv = new ModelAndView("BRRS/M_AIDP");

		try {
			Date d1 = dateformat.parse(todate);

			/* ===================== ARCHIVAL ===================== */
			if ("ARCHIVAL".equalsIgnoreCase(type)) {

				// 🔹 ARCHIVAL → DETAIL
				if ("detail".equalsIgnoreCase(dtltype)) {

					mv.addObject("reportsummary", getAIDPArchivalDetail1ByDateVersion(d1, version));
					mv.addObject("reportsummary2", getAIDPArchivalDetail2ByDateVersion(d1, version));
					mv.addObject("reportsummary3", getAIDPArchivalDetail3ByDateVersion(d1, version));
					mv.addObject("reportsummary4", getAIDPArchivalDetail4ByDateVersion(d1, version));

					mv.addObject("displaymode", "detail");
				} else if ("report".equalsIgnoreCase(dtltype)) {

					mv.addObject("reportsummary", getAIDPArchivalSummary1ByDateVersion(d1, version));
					mv.addObject("reportsummary2", getAIDPArchivalSummary2ByDateVersion(d1, version));
					mv.addObject("reportsummary3", getAIDPArchivalSummary3ByDateVersion(d1, version));
					mv.addObject("reportsummary4", getAIDPArchivalSummary4ByDateVersion(d1, version));

					mv.addObject("displaymode", "summary");
				}
				// 🔹 ARCHIVAL → SUMMARY
				else {

					mv.addObject("reportsummary", getAIDPArchivalSummary1ByDateVersion(d1, version));
					mv.addObject("reportsummary2", getAIDPArchivalSummary2ByDateVersion(d1, version));
					mv.addObject("reportsummary3", getAIDPArchivalSummary3ByDateVersion(d1, version));
					mv.addObject("reportsummary4", getAIDPArchivalSummary4ByDateVersion(d1, version));

					mv.addObject("displaymode", "summary");
				}
			}

			else if ("RESUB".equalsIgnoreCase(type)) {

				// 🔹 ARCHIVAL → DETAIL
				if ("detail".equalsIgnoreCase(dtltype)) {

					mv.addObject("reportsummary", getAIDPResubDetail1ByDateVersion(d1, version));
					mv.addObject("reportsummary2", getAIDPResubDetail2ByDateVersion(d1, version));
					mv.addObject("reportsummary3", getAIDPResubDetail3ByDateVersion(d1, version));
					mv.addObject("reportsummary4", getAIDPResubDetail4ByDateVersion(d1, version));

					mv.addObject("displaymode", "detail");
				} else if ("report".equalsIgnoreCase(dtltype)) {

					mv.addObject("reportsummary", getAIDPResubSummary1ByDateVersion(d1, version));
					mv.addObject("reportsummary2", getAIDPResubSummary2ByDateVersion(d1, version));
					mv.addObject("reportsummary3", getAIDPResubSummary3ByDateVersion(d1, version));
					mv.addObject("reportsummary4", getAIDPResubSummary4ByDateVersion(d1, version));

					mv.addObject("displaymode", "summary");
				}
				// 🔹 ARCHIVAL → SUMMARY
				else {

					mv.addObject("reportsummary", getAIDPResubSummary1ByDateVersion(d1, version));
					mv.addObject("reportsummary2", getAIDPResubSummary2ByDateVersion(d1, version));
					mv.addObject("reportsummary3", getAIDPResubSummary3ByDateVersion(d1, version));
					mv.addObject("reportsummary4", getAIDPResubSummary4ByDateVersion(d1, version));

					mv.addObject("displaymode", "summary");
				}
			}

			/* ===================== NORMAL ===================== */
			else {

				// 🔹 NORMAL → DETAIL
				if ("detail".equalsIgnoreCase(dtltype)) {

					mv.addObject("reportsummary", getAIDPDetail1(d1));
					mv.addObject("reportsummary2", getAIDPDetail2(d1));
					mv.addObject("reportsummary3", getAIDPDetail3(d1));
					mv.addObject("reportsummary4", getAIDPDetail4(d1));

					mv.addObject("displaymode", "detail");
				}
				// 🔹 NORMAL → SUMMARY
				else {

					mv.addObject("reportsummary", getAIDPSummary1(d1));
					mv.addObject("reportsummary2", getAIDPSummary2(d1));
					mv.addObject("reportsummary3", getAIDPSummary3(d1));
					mv.addObject("reportsummary4", getAIDPSummary4(d1));

					mv.addObject("displaymode", "summary");
				}
			}

		} catch (ParseException e) {
			e.printStackTrace();
		}

		return mv;
	}

	@Transactional
	public void updateReport(BRRS_M_AIDP_Summary_Entity1 updatedEntity) {

		System.out.println("Came to services");
		System.out.println("Report Date: " + updatedEntity.getREPORT_DATE());

		BRRS_M_AIDP_Summary_Entity1 existing = findAIDPSummary1(updatedEntity.getREPORT_DATE());

		BRRS_M_AIDP_Detail_Entity1 existing1 = findAIDPDetail1(updatedEntity.getREPORT_DATE());

		// Audit old copy
		BRRS_M_AIDP_Summary_Entity1 oldcopy = new BRRS_M_AIDP_Summary_Entity1();
		BeanUtils.copyProperties(existing, oldcopy);

		try {

			// 1️⃣ Loop R11 to R50
			for (int i = 11; i <= 50; i++) {

				String prefix = "R" + i + "_";

				String[] fields = { "NAME_OF_BANK", "TYPE_OF_ACC", "PURPOSE", "CURRENCY", "BANK_RATE",
						"AMT_LESS_184_DAYS", "AMT_MORE_184_DAYS" };

				for (String field : fields) {

					String getterName = "get" + prefix + field;
					String setterName = "set" + prefix + field;

					try {

						Method getter = BRRS_M_AIDP_Summary_Entity1.class.getMethod(getterName);

						Object newValue = getter.invoke(updatedEntity);

						// Summary update
						Method summarySetter = BRRS_M_AIDP_Summary_Entity1.class.getMethod(setterName,
								getter.getReturnType());

						summarySetter.invoke(existing, newValue);

						// Detail update
						Method detailSetter = BRRS_M_AIDP_Detail_Entity1.class.getMethod(setterName,
								getter.getReturnType());

						detailSetter.invoke(existing1, newValue);

					} catch (NoSuchMethodException e) {
						continue;
					}
				}
			}

			// 2️⃣ Handle R51 Totals
			String[] totalFields = { "TOT_AMT_LESS_184_DAYS", "TOT_AMT_MORE_184_DAYS" };

			for (String field : totalFields) {

				String getterName = "getR51_" + field;
				String setterName = "setR51_" + field;

				try {

					Method getter = BRRS_M_AIDP_Summary_Entity1.class.getMethod(getterName);

					Object newValue = getter.invoke(updatedEntity);

					Method summarySetter = BRRS_M_AIDP_Summary_Entity1.class.getMethod(setterName,
							getter.getReturnType());

					summarySetter.invoke(existing, newValue);

					Method detailSetter = BRRS_M_AIDP_Detail_Entity1.class.getMethod(setterName,
							getter.getReturnType());

					detailSetter.invoke(existing1, newValue);

				} catch (NoSuchMethodException e) {
					continue;
				}
			}

		} catch (Exception e) {

			throw new RuntimeException("Error while updating report fields", e);
		}

		// Audit & Save only if changes exist
		String changes = auditService.getChanges(oldcopy, existing);

		if (!changes.isEmpty()) {

			saveAIDPSummary1(existing);
			saveAIDPDetail1(existing1);

			auditService.compareEntitiesmanual(oldcopy, existing, updatedEntity.getREPORT_DATE().toString(),
					"M AIDP Summary Screen", "BRRS_M_AIDP_SUMMARY");
		}
	}

