	private <T> List<T> queryList(String sql, Class<T> type, Object... args) {
		return jdbcTemplate.query(sql, BeanPropertyRowMapper.newInstance(type), args);
	}

	private <T> T querySingle(String sql, Class<T> type, Object... args) {
		try {
			return jdbcTemplate.queryForObject(sql, BeanPropertyRowMapper.newInstance(type), args);
		} catch (EmptyResultDataAccessException e) {
			throw new RuntimeException("AIDP record not found", e);
		}
	}

	private <T> List<T> queryByDateVersion(String tableName, Class<T> type, Date reportDate, BigDecimal reportVersion) {
		return queryList("SELECT * FROM " + tableName + " WHERE REPORT_DATE = ? AND REPORT_VERSION = ?", type,
				reportDate, reportVersion);
	}

	private <T> List<T> queryAll(String tableName, Class<T> type) {
		return queryList("SELECT * FROM " + tableName, type);
	}

	private <T> T queryByDate(String tableName, Class<T> type, Date reportDate) {
		return querySingle("SELECT * FROM " + tableName + " WHERE REPORT_DATE = ?", type, reportDate);
	}

	private <T> void saveByKeys(String tableName, T entity, String... keyColumns) {
		try {
			List<Field> fields = new ArrayList<>();
			Class<?> current = entity.getClass();
			while (current != null && current != Object.class) {
				Collections.addAll(fields, current.getDeclaredFields());
				current = current.getSuperclass();
			}
			Map<String, Object> values = new LinkedHashMap<>();
			for (Field field : fields) {
				if (java.lang.reflect.Modifier.isStatic(field.getModifiers()))
					continue;
				field.setAccessible(true);
				values.put(toColumnName(field.getName()), field.get(entity));
			}
			StringBuilder updateSql = new StringBuilder("UPDATE ").append(tableName).append(" SET ");
			List<Object> updateParams = new ArrayList<>();
			boolean first = true;
			for (Map.Entry<String, Object> entry : values.entrySet()) {
				if (isKeyColumn(entry.getKey(), keyColumns))
					continue;
				if (!first)
					updateSql.append(", ");
				updateSql.append(entry.getKey()).append(" = ?");
				updateParams.add(entry.getValue());
				first = false;
			}
			appendWhere(updateSql, updateParams, values, keyColumns);
			if (jdbcTemplate.update(updateSql.toString(), updateParams.toArray()) > 0)
				return;
			StringBuilder insertSql = new StringBuilder("INSERT INTO ").append(tableName).append(" (");
			StringBuilder placeholders = new StringBuilder(" VALUES (");
			List<Object> insertParams = new ArrayList<>();
			first = true;
			for (Map.Entry<String, Object> entry : values.entrySet()) {
				if (!first) {
					insertSql.append(", ");
					placeholders.append(", ");
				}
				insertSql.append(entry.getKey());
				placeholders.append("?");
				insertParams.add(entry.getValue());
				first = false;
			}
			insertSql.append(")").append(placeholders).append(")");
			jdbcTemplate.update(insertSql.toString(), insertParams.toArray());
		} catch (IllegalAccessException e) {
			throw new RuntimeException("Unable to save AIDP record", e);
		}
	}

	private void appendWhere(StringBuilder sql, List<Object> params, Map<String, Object> values, String... keyColumns) {
		sql.append(" WHERE ");
		for (int i = 0; i < keyColumns.length; i++) {
			if (i > 0)
				sql.append(" AND ");
			sql.append(keyColumns[i]).append(" = ?");
			params.add(values.get(keyColumns[i]));
		}
	}

	private boolean isKeyColumn(String columnName, String... keyColumns) {
		for (String keyColumn : keyColumns)
			if (keyColumn.equalsIgnoreCase(columnName))
				return true;
		return false;
	}

	private String toColumnName(String fieldName) {
		if (fieldName.equals("reportResubDate"))
			return "REPORT_RESUBDATE";
		return fieldName.toUpperCase(Locale.ROOT);
	}

