	private List<Object[]> getAIDPArchivalRows(int section) {
		return jdbcTemplate.query(
				"SELECT REPORT_DATE, REPORT_VERSION, REPORT_RESUBDATE FROM BRRS_M_AIDP_ARCHIVALTABLE_SUMMARY" + section
						+ " ORDER BY REPORT_VERSION",
				(rs, rowNum) -> new Object[] { rs.getDate("REPORT_DATE"), rs.getBigDecimal("REPORT_VERSION"),
						rs.getDate("REPORT_RESUBDATE") });
	}

	private List<Object[]> getAIDPResubRows(int section) {
		return jdbcTemplate.query(
				"SELECT REPORT_DATE, REPORT_VERSION, REPORT_RESUBDATE FROM BRRS_M_AIDP_RESUBTABLE_SUMMARY" + section
						+ " WHERE REPORT_VERSION IS NOT NULL ORDER BY REPORT_VERSION",
				(rs, rowNum) -> new Object[] { rs.getDate("REPORT_DATE"), rs.getBigDecimal("REPORT_VERSION"),
						rs.getDate("REPORT_RESUBDATE") });
	}

	private BigDecimal findAIDPResubMaxVersion(int section) {
		BigDecimal v = jdbcTemplate.queryForObject(
				"SELECT COALESCE(MAX(REPORT_VERSION), 0) FROM BRRS_M_AIDP_RESUBTABLE_SUMMARY" + section,
				BigDecimal.class);
		return v == null ? BigDecimal.ZERO : v;
	}

